# OEIS sequence: A122525

from math import factorial
def Trow(n: int) -> list[int]: # is (0, 0)-based!
    val = factorial(n); row = [val]
    for k in range(n - 1, -1, -1):
        val = (val * (n + 1) * (k + 1)) // ((n - k) * (k + 2))
        row.append(val)
    return row
def T(n: int, k: int) -> int:  # is (1, 1)-based!
    return Trow(n - 1)[k - 1]
